uint64_t overflow_part = encoded_rho >> DENSE_BUCKET_SIZE;  // Upper bits

if (overflow_part > 0) {
  // Need overflow: set dense to max (15)
  uint64_t current_dense = dense_bucket_[j].to_ullong();
  dense_bucket_[j] = std::bitset<DENSE_BUCKET_SIZE>(std::max(current_dense, 15ULL));

